# Category: race_condition

local rate = 10 -- Requests per second
local window = 1 -- Second window

local dict = ngx.shared.DICT

function limit()
    local key = ngx.var.remote_addr
    local now = ngx.time()

    local value = dict:get(key)
    if value then
        local timestamp, count = string.match(value, "^(%d+):(%d+)$")
        if now - tonumber(timestamp) > window then
            dict:set(key, now .. ":0")
            return true
        else
            if count >= rate then
                return false
            else
                local new_count = count + 1
                dict:set(key, timestamp .. ":" .. new_count)
                return true
            end
        end
    else
        dict:set(key, now .. ":1")
        return true
    end
end

if not limit() then
    ngx.status = 429
    ngx.say("Rate limit exceeded")
    ngx.exit(429)
end